const fs = require('fs');
const path = require('path');
const jsonPath = path.join(__dirname, 'curriculumIndex.json');
const data = JSON.parse(fs.readFileSync(jsonPath, 'utf8'));

function up(pageId, elos, scos, eloGroups) {
  const page = data.indexedPages.find(p => p.id === pageId);
  if (!page) { console.log('MISSING:', pageId); return; }
  page.essentialOutcomes = elos;
  page.specificOutcomes = scos;
  page.eloGroups = eloGroups;
  console.log('OK:', pageId, 'E:' + elos.length, 'S:' + scos.length);
}

